public class RecordMethod {
    record Vector(double x, double y) {
        double magnitude() { return Math.sqrt(x * x + y * y); }
        Vector scale(double factor) { return new Vector(x * factor, y * factor); }
    }
    public static void main(String[] args) {
        Vector v = new Vector(3, 4);
        System.out.println(v.magnitude());
        Vector v2 = v.scale(2);
        System.out.println(v2);
    }
}
